&lt;div class=&quot;content-intro&quot;&gt;&lt;p style=&quot;text-align: justify;&quot;&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); font-size: 12pt;&quot;&gt;&lt;strong&gt;A Little About Us&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
